BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?req ?name WHERE {
  ?pkg vocab:NamedElement_name "APS Performance Requirements" .
  ?pkg vocab:Element_ownedElement+ ?req .
  ?req rdf:type <http://api.koneksys.com/cameo/vocab/tmt%20requirement> .
  OPTIONAL { ?req vocab:NamedElement_name ?name }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?req ?name ?constraint ?spec WHERE {
  ?req rdf:type <http://api.koneksys.com/cameo/vocab/tmt%20requirement> .
  ?req vocab:NamedElement_name ?name .
  FILTER(CONTAINS(LCASE(STR(?name)), LCASE("APS"))) 
  OPTIONAL { ?req <http://api.koneksys.com/cameo/vocab/Constraint_specification> ?spec }
  OPTIONAL { ?req <http://api.koneksys.com/cameo/vocab/Constraint_constrainedElement> ?constraint }
}
LIMIT 50

