PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?inv ?invName ?ownerName ?timeValue WHERE {
  ?constraint rdf:type <http://api.koneksys.com/cameo/vocab/time%20constraint> .
  ?constraint <http://api.koneksys.com/cameo/vocab/Constraint_constrainedElement> ?inv .
  ?inv rdf:type <http://api.koneksys.com/cameo/vocab/state%20invariant> .
  OPTIONAL { ?inv vocab:NamedElement_name ?invName }
  OPTIONAL { ?inv vocab:Element_owner ?owner }
  OPTIONAL { ?owner vocab:NamedElement_name ?ownerName }
  OPTIONAL { ?constraint <http://api.koneksys.com/cameo/vocab/TimeConstraint_specification__from_TimeConstraint> ?interval }
  OPTIONAL { ?interval <http://api.koneksys.com/cameo/vocab/TimeInterval_min__from_TimeInterval> ?timeExpr }
  OPTIONAL { ?timeExpr <http://api.koneksys.com/cameo/vocab/TimeExpression_expr> ?duration }
  OPTIONAL { ?duration <http://api.koneksys.com/cameo/vocab/Duration_expr> ?lit }
  OPTIONAL { ?lit rdf:type <http://api.koneksys.com/cameo/vocab/literal%20string> }
  OPTIONAL { ?lit <http://api.koneksys.com/cameo/vocab/LiteralString_value> ?timeValue }
  FILTER(CONTAINS(LCASE(STR(?ownerName)), LCASE("APS")) || CONTAINS(LCASE(STR(?invName)), LCASE("APS")))
  FILTER(CONTAINS(STR(?timeValue), "s") && !CONTAINS(STR(?timeValue), "http"))
